        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);

    // Vector: only set V flag if QEMU advertised the V extension. vlenb
    // bounds the per-register byte count copied into vreg[].
    s.vstart = read_reg64(v->vstart);
