// Enables the vsim->QEMU handoff drain. After this is set, run() watches
// committed PCs and on retire of a `csrw 0x7C0, *` exit-trigger drains
// architectural state to `state_out_path` and returns kExitHandoffToQemu.
void enable_hybrid_handoff(const std::string& elf_path,
                           const std::string& state_out_path)
{
  auto elf = LIEF::ELF::Parser::parse(elf_path);
  if (!elf)
    throw std::runtime_error(
      "enable_hybrid_handoff: failed to parse " + elf_path);

  hybrid::CsrTrigger trigger;
  for (const auto& seg: elf->segments()) {
    if (seg.type() != LIEF::ELF::SEGMENT_TYPES::PT_LOAD) continue;
    if ((static_cast<unsigned>(seg.flags()) & 1u) == 0u) continue;  // PF_X
    const auto content = seg.content();
    const std::span<const uint8_t> bytes{content.data(), content.size()};
    trigger.scan_buffer(bytes, seg.virtual_address());
  }

  hybrid_dmi_bus_ = std::make_unique<
    hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
                          PLATFORM::dmi_data_width>>(platform.dmi,
                                                     platform.clk.period());
  hybrid_handoff_.emplace(std::move(trigger), *hybrid_dmi_bus_);
  if (hybrid_input_state_)
    hybrid_handoff_->set_passthrough_input(*hybrid_input_state_);
  hybrid_state_path_ = state_out_path;
}

void restore_context(const std::string& dir)
{
  context_config.dir = dir;
  context_config.restore(platform, cpu);
}

void save_context(const std::string& dir)
{
  context_config.dir = dir;
  context_config.save(platform, cpu);
}

void load_elf(const std::string& path)
{
  const auto elf = LIEF::ELF::Parser::parse(path);
  if (!elf) {
    spdlog::critical("Check if it's a valid ELF file path : {}", path);
    exit(1);
  }

  read_elf_into_memory(
    *elf,
    static_cast<xlen_t>(platform.main_memory.region.base_address),
    platform.main_memory.data);
  for (auto& rv: platform.reset_vector)
    rv.write(elf->entrypoint());

