// rt_long_roi.S
//
// Tier-1 fixture: a non-trivial vsim ROI that exercises branch + decode
// through the cycle-accurate pipeline for many cycles. Catches resume-state
// corruption that only manifests after a long sequence of dependent
// instructions.
//
// Phase A (QEMU1): seed t0 = 100 (loop count), t1 = 0 (sum).
// Phase B (vsim):  for i = 100 down to 1, t1 += i. Final t1 = 5050.
// Phase C (QEMU2): verify t1 == 5050; exit 0 on PASS, 1 on FAIL.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    li      t0, 100                  // loop counter
    li      t1, 0                    // running sum

    csrwi   0x7C0, 0                 // QEMU1 drains, exits

    // Phase B: 100-iteration sum loop.
loop:
    add     t1, t1, t0
    addi    t0, t0, -1
    bnez    t0, loop

    csrwi   0x7C0, 1                 // vsim drains, exits 200

phase_c:
    li      t2, 5050
    beq     t1, t2, pass
    li      a2, 1
    SEMIHOST_EXIT a2
pass:
    li      a2, 0
    SEMIHOST_EXIT a2

// rt_mem_loadstore.S
//
// Tier-1 fixture: vsim memory subsystem under load while running from
// foreign architectural state. Exercises store, load-after-store, and a
// modify-store-reload sequence. Memory written in Phase A would be lost
// (no shared mmap in Tier-1), so all initialization happens in Phase B.
//
// Phase A (QEMU1): csrwi 0x7C0, 0 -> drain & exit (no memory work).
// Phase B (vsim):
//   1. buf[i] = (i+1) << 56   for i in 0..7    (8 doublewords at 0x80003000).
//   2. buf[i] += 1.
//   3. x10 = sum(buf[0..7]).
//   Final x10 = 0x2400_0000_0000_0008
//                = (1+2+...+8)<<56 + 8.
// Phase C (QEMU2): verify x10; exit 0 on PASS, 1 on FAIL.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    csrwi   0x7C0, 0                 // QEMU1 drains, exits

    // Phase B begin.
    li      t0, 0x80003000           // buf base
    li      t1, 0x0100000000000000   // step = 1 << 56

    // Pass 1: write buf[i] = (i+1) * step.
    mv      t2, t1                   // running value (starts at step for i=0)
    mv      t4, t0                   // walking ptr
    li      t3, 8
1:
    sd      t2, 0(t4)
    add     t2, t2, t1
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    // Pass 2: buf[i] += 1.
    mv      t4, t0
    li      t3, 8
1:
    ld      t2, 0(t4)
    addi    t2, t2, 1
    sd      t2, 0(t4)
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    // Pass 3: x10 = sum(buf[0..7]).
    mv      t4, t0
    li      t3, 8
    li      x10, 0
1:
    ld      t2, 0(t4)
    add     x10, x10, t2
    addi    t4, t4, 8
    addi    t3, t3, -1
    bnez    t3, 1b

    csrwi   0x7C0, 1                 // vsim drains, exits 200

phase_c:
    li      t0, 0x2400000000000000
    addi    t0, t0, 8
    beq     x10, t0, pass
    li      a2, 1
    SEMIHOST_EXIT a2
pass:
    li      a2, 0
    SEMIHOST_EXIT a2

// rt_shared_mem.S
//
// Tier-2 fixture: cross-simulator memory survival via shared mmap.
// Unlike Tier-1 fixtures, all three phases see the same backing file via
// QEMU's `-object memory-backend-file,share=on` and vsim's
// `--shared-mem-path`. Memory written in Phase A is visible in Phase B; the
// page Phase B mutates is visible in Phase C.
//
// Phase A (QEMU1, shared mmap): fill 4 KB at 0x80010000 with 0xA5A5..A5.
// Phase B (vsim, same mmap):
//   1. read back; first mismatch -> exit 50.
//   2. XOR every word with 0x5A5A..5A in place; result is all-FF.
// Phase C (QEMU2, same mmap):
//   1. verify all 4 KB == 0xFF; first mismatch -> exit 51.
//   2. exit 0 on PASS.
//
// Distinct exit codes (50, 51) avoid the silent-pass aliasing that a
// running mismatch counter would have when (count mod 256) lands on 0.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    // Phase A: fill 512 doublewords at 0x80010000 with 0xA5A5...A5.
    li      t0, 0x80010000
    li      t3, 0xA5A5A5A5A5A5A5A5
    li      t1, 512
1:
    sd      t3, 0(t0)
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, 1b

    csrwi   0x7C0, 0                        // QEMU1 drains, exits

    // Phase B: verify Phase A pattern, XOR with 0x5A...5A in place.
    li      t0, 0x80010000
    li      t3, 0xA5A5A5A5A5A5A5A5
    li      t4, 0x5A5A5A5A5A5A5A5A
    li      t1, 512
verify_a:
    ld      t2, 0(t0)
    bne     t2, t3, fail_b
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, verify_a

    li      t0, 0x80010000
    li      t1, 512
xor_loop:
    ld      t2, 0(t0)
    xor     t2, t2, t4
    sd      t2, 0(t0)
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, xor_loop

    csrwi   0x7C0, 1                        // vsim drains, exits 200

phase_c:
    // Phase C: verify all 4 KB == 0xFFFF...FF through the shared mmap.
    li      t0, 0x80010000
    li      t5, -1                          // sign-extends to 0xFFFF...FF
    li      t1, 512
verify_c:
    ld      t2, 0(t0)
    bne     t2, t5, fail_c
    addi    t0, t0, 8
    addi    t1, t1, -1
    bnez    t1, verify_c

    li      a2, 0
    SEMIHOST_EXIT a2

fail_b:
    li      a2, 50
    SEMIHOST_EXIT a2

fail_c:
    li      a2, 51
    SEMIHOST_EXIT a2

// rt_unaligned_lh.S
//
// Tier-1 fixture: halfword/byte loads at unaligned addresses inside the
// vsim ROI. Stresses the LSU on byte- and halfword-granular paths that
// the existing fixtures (which only do doubleword sd/ld) never touch.
//
// Phase A (QEMU1): csrwi 0x7C0, 0 -> drain & exit.
// Phase B (vsim):
//   sd  0x8070605040302010 -> [0x80003000]   (LE: byte[0]=0x10, ..., byte[7]=0x80)
//   lh  t2, 1(t0)   -> 0x3020 (sign-ext positive)
//   lb  t2, 3(t0)   -> 0x40   (sign-ext positive)
//   lhu t2, 5(t0)   -> 0x7060 (unsigned)
//   x10 = 0x3020 + 0x40 + 0x7060 = 0xA0C0
// Phase C (QEMU2): verify x10 == 0xA0C0; exit 0 on PASS, 1 on FAIL.

#include "semihost_exit.inc"

.section .text
.globl _start
_start:
    csrwi   0x7C0, 0                 // QEMU1 drains, exits

    // Phase B begin.
    li      t0, 0x80003000
    li      t1, 0x8070605040302010
    sd      t1, 0(t0)

    li      x10, 0
    lh      t2, 1(t0)
    add     x10, x10, t2
    lb      t2, 3(t0)
    add     x10, x10, t2
    lhu     t2, 5(t0)
    add     x10, x10, t2

    csrwi   0x7C0, 1                 // vsim drains, exits 200

phase_c:
    li      t0, 0xA0C0
    beq     x10, t0, pass
    li      a2, 1
    SEMIHOST_EXIT a2
pass:
    li      a2, 0
    SEMIHOST_EXIT a2

